mapper.select:
select

from runs
where session_id = #{sessionId}
  and client_request_id = #{clientRequestId}

mapper.update:
update sessions
set opencode_session_id = #{binding.remoteSessionId},
    opencode_execution_node_id = #{binding.executionNodeId.value},
    updated_at = #{binding.updatedAt},
    trace_id = #{binding.traceId}
where session_id = #{binding.sessionId.value}

mapper.insert:
merge into session_messages as target using (values
( #{row.messageId}, #{row.sessionId}, #{row.role}, #{row.content}, #{row.traceId}, cast(#{row.createdAt} as timestamp), #{row.runId}, #{row.agentId}, #{row.remoteMessageId}, cast(null as varchar), cast(#{row.updatedAt} as timestamp), #{row.sourceType}, #{row.sourceRefId}, #{row.senderUserId}, #{row.contentKind}, #{row.summaryKey}, #{row.summaryVersion}, #{row.summaryStatus} )
) as source( message_id, session_id, role, content, trace_id, created_at, run_id, agent_id, remote_message_id, parts_json, updated_at, source_type, source_ref_id, sender_user_id, content_kind, summary_key, summary_version, summary_status ) on target.summary_key = source.summary_key when matched then update set session_id = source.session_id, role = source.role, content = source.content, trace_id = source.trace_id, run_id = source.run_id, agent_id = source.agent_id, remote_message_id = source.remote_message_id, parts_json = cast(null as varchar), updated_at = source.updated_at, source_type = source.source_type, source_ref_id = source.source_ref_id, sender_user_id = source.sender_user_id, content_kind = source.content_kind, summary_version = source.summary_version, summary_status = source.summary_status when not matched then insert ( message_id, session_id, role, content, trace_id, created_at, run_id, agent_id, remote_message_id, parts_json, updated_at, source_type, source_ref_id, sender_user_id, content_kind, summary_key, summary_version, summary_status ) values ( source.message_id, source.session_id, source.role, source.content, source.trace_id, source.created_at, source.run_id, source.agent_id, source.remote_message_id, source.parts_json, source.updated_at, source.source_type, source.source_ref_id, source.sender_user_id, source.content_kind, source.summary_key, source.summary_version, source.summary_status )

mapper.update:
update sessions
set updated_at = #{updatedAt}
where session_id = #{sessionId}
